import pytest

@pytest.mark.parametrize("deposit,expected_status", [
    (1500,  201),
    (10,    422),
    (60000, 422),
])
def test_open_checking_decision_table_verified_valid_deposit(
    verified_customer_client, deposit, expected_status
):
    payload = {"initial_deposit": deposit, "account_type": "checking"}
    resp = verified_customer_client.post("/accounts/checking", json=payload)
    assert resp.status_code == expected_status
